#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M,K; scanf("%d %d %d",&N,&M,&K);
        int *freq = calloc(N+2, sizeof(int));
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            if(x<=N) freq[x]++;
        }
        if(M < K){
            printf("NO\n");
            free(freq);
            continue;
        }
        int ok = 1;
        for(int i=0;i<K;i++) if(freq[i]==0){ ok=0; break; }
        if(!ok){ printf("NO\n"); free(freq); continue; }
        int nonK = N - freq[K];
        if(nonK >= M) printf("YES\n"); else printf("NO\n");
        free(freq);
    }
    return 0;
}

