import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); K = int(next(it))
        freq = [0]*(N+2)
        for _ in range(N):
            x = int(next(it))
            if x <= N:
                freq[x] += 1
        if M < K:
            out.append('NO'); continue
        ok = all(freq[i] > 0 for i in range(K))
        if not ok:
            out.append('NO'); continue
        nonK = N - freq[K]
        out.append('YES' if nonK >= M else 'NO')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

